VALUES
  ('aboriginal-e3452428-moex-00261', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-111-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '關於行政機關之組織，下列敘述何者非憲法之明文規定？', '["行政院之組織，應以法律定之", "應以行政院為行政層級中之最高行政機關", "立法院不得於作用法中規定具組織法性質之規範", "行政院所屬各級機關之設置與組織，立法院得以準則性法律，為框架性規範"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:58+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "502", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00262', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-111-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '下列何者非屬司法機關？', '["懲戒法院之職務法庭", "少年及家事法院", "公務人員保障暨培訓委員會", "司法院大法官"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:58+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "502", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00263', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-111-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '基於住民自治之理念與垂直分權之功能，下列敘述何者錯誤？', '["地方自治團體設有地方行政機關及立法機關", "地方自治團體首長與民意代表均由自治區域內之人民依法選舉產生", "地方立法機關議決之預算拘束地方行政機關，地方行政機關不得提出覆議", "中央政府對地方自治團體依法得依事件之性質為適法性或適當性監督"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:58+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "502", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00264', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-111-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '下列關於「原住民族地區」的敘述，何者錯誤？', '["我國於90年10月31日公布施行之原住民族工作權保障法，規定「原住民地區」中之各級政府機 關、公立學校及公營事業機構，其僱用特定人員之總額中，原住民的人數應達一定比例之門檻", "原住民族委員會於民國91年報請行政院核定30個山地鄉及25個平地鄉（鎮、市）為原住民地區", "我國於94年2月5日公布施行之原住民族基本法中，對於「原住民族地區」之定義，乃沿用原住 民族工作權保障法之規定，亦即「原住民傳統居住，具有原住民族歷史淵源及文化特色，經中央原 住民族主管機關報請行政院核定之地區」。至於「原住民族地區」之具體範圍，則承襲民國91年行 政院所核定之「原住民地區」範圍", "原住民族基本法中，對於部落之定義，亦和「原住民族地區」有關，其「係指原住民於原住民族 地區一定區域內，依其傳統規範共同生活結合而成之團體，經中央原住民族主管機關報請行政院 核定者」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:58+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "502", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00265', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-111-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '民國110年9月，最高法院作成第108年度台上大字第1636號裁定（併案：109年度台上字第1302 號及110年度台上字第709號），對於非原住民透過借名登記，取得原住民保留地使用之情形，裁定 借名登記、買賣契約違反民法第71條本文規定，應屬無效。下列何者非屬本裁定所採取的理由？', '["憲法增修條文第10條第12項，即已揭示國家應保障原住民族之地位，對其經濟土地予以保障扶助 並促其發展", "山坡地保育利用條例第37條，以及原住民保留地開發管理辦法第18條，都明訂原住民取得原住民 保留地所有權後，除政府指定之特定用途外，其移轉之承受人以原住民為限", "民法第71條本文規定，法律行為違反強制或禁止之規定者，無效。非原住民藉法律行為以規避山 坡地保育利用條例第37條、原住民保留地開發管理辦法第18條之禁止規定，悖於保護原住民族意 旨，該法律行為應屬無效", "原住民族基本法第20條明訂，政府承認原住民族土地及自然資源權利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:58+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "502", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00266', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-111-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '地方制度法中，有關於山地鄉之鄉長，因辭職、去職、死亡、停職等原因出缺時的規範，下列敘述何 者正確？', '["由原住民族委員會派員代理", "自事實發生之日起6個月內完成補選。但所遺任期不足2年者，不再補選，由代理人代理至該屆任 期屆滿為止", "代理人不得為被代理者之配偶、前配偶、四親等內之血親、三親等內之姻親關係", "山地鄉鄉長以山地原住民為限，但因辭職、去職、死亡、停職等原因出缺時之代理人，不受此限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:58+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "502", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00267', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-111-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '根據諮商取得原住民族部落同意參與辦法第4條，原住民族基本法第21條所稱原住民族或部落同意， 指過半數關係部落依本辦法召開部落會議議決通過；所稱原住民族或部落參與，指過半數關係部落依 本辦法召開部落會議議決通過之參與機制。下列關於「關係部落」的說明，何者正確？', '["關係部落，是指和同意事項發生所在地部落，具血緣以及地緣相關性之部落", "關係部落由同意事項所在地之鄉（鎮、市、區）公所認定之；認定有困難時，應敘明爭議事項及處 理意見，報請中央原住民族主管機關認定", "關係部落之部落會議主席自收受同意事項之通知，逾二個月未召集部落會議時，申請人得自行代行 召集", "關係部落得聯合召集部落會議議決同意事項。前項部落會議，由關係部落之各部落會議主席共同主持"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:58+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "502", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00268', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-111-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '原住民族文化資產處理辦法中，有關於原住民族無形文化資產、文化資產保存技術之登錄及保存者之 認定程序的規範，不包含下列那一個項目？', '["會同原住民族主管機關，並邀請所屬原住民族、部落或其他傳統組織及利益團體，進行現場勘查。 但無法知悉所屬部落或其他傳統組織及利益團體者，不在此限", "辦理公聽會、說明會或其他適當方式諮商相關原住民族、部落或其他傳統組織", "經主管機關召開原住民族文化資產審議會審議通過後，作成指定或登錄處分，辦理公告，並通知申 請人或處分相對人", "直轄市、縣（市）主管機關指定或登錄後，應報中央主管機關核定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:58+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "502", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00269', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-111-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '原住民族傳統智慧創作保護條例，乃是為促進原住民族文化發展，依原住民族基本法第13條之規定 所制定。其對智慧創作專用權之規範，不包含下列那一項？', '["智慧創作專用權，指智慧創作財產權及智慧創作人格權", "智慧創作專用權人享有下列智慧創作人格權，包括專有禁止他人以歪曲、割裂、竄改或其他方法改 變其智慧創作之內容、形式或名目致損害其名譽之創作人格權", "智慧創作專用權依規定為原住民族或部落取得者，其智慧創作之收入，應以原住民族或部落利益為 目的，設立共同基金", "智慧創作專用權不得為讓與、設定質權及作為為強制執行之標的，但經主管機關同意者，不在此限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:58+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "502", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00270', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-111-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '根據山坡地保育利用條例第37條，原住民取得原住民保留地所有權，如有移轉，以原住民為限，但 有特定情形者，得由政府承受私有原住民保留地，下列何者屬於得由政府承受私有原住民保留地之特 定情形？', '["興辦依土地徵收條例第3條（因公益需要之徵收）、第4條第1項（區段徵收）規定之各款事業及 所有權人依該條例第8條規定申請一併徵收", "經中央原住民族主管機關審認符合轉換作為傳統領域土地之需求", "稅捐稽徵機關受理以原住民保留地抵繳增值稅", "因私法金錢給付義務之執行事件未能拍定原住民保留地"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:58+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "502", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL)
